{
  "formal_minutes": {
    "회의명": "UI Theme Package Release Readiness",
    "프로젝트_코드": "PUBLIC_MEETING_SMOKE",
    "참석자": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "확정_결정": [
      {
        "내용": "공개 릴리스 목표는 smoke test가 통과할 경우 금요일 15:00 KST로 한다.",
        "조건": "smoke test 통과"
      },
      {
        "내용": "packageName mismatch가 발생하면 먼저 package config를 확인한다."
      },
      {
        "내용": "contract 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."
      }
    ],
    "거절된_제안": [
      {
        "제안": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "제안자": "Hara",
        "결론": "거절됨"
      }
    ],
    "내부_스트레치_목표": [
      {
        "내용": "수요일 릴리스",
        "제안자": "Seoyeon",
        "결론": "최종 릴리스 결정이 아니며 내부 stretch goal로만 취급"
      }
    ],
    "비결정사항": [
      {
        "내용": "README install steps를 목요일까지 가능하면 검토한다.",
        "상태": "소유자 미지정"
      },
      {
        "내용": "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부",
        "상태": "결정되지 않음"
      }
    ],
    "리스크": [
      "잘못된 tarball path는 릴리스를 지연시킬 수 있다.",
      "README install steps가 오래된 경우 릴리스 노트가 사용자에게 오해를 줄 수 있다."
    ],
    "미해결_질문": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "명시됨"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 failure triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "명시됨"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke results를 게시한 뒤 generated tarball path를 확인한다.",
      "due": null,
      "status": "확정, 정확한 마감 없음",
      "source_certainty": "명시됨"
    },
    {
      "owner": null,
      "task": "README install steps를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능하면",
      "status": "소유자 미지정",
      "source_certainty": "부분 명시됨"
    }
  ],
  "followup_note": {
    "다음_확인사항": [
      "Minjun의 smoke test 결과가 금요일 10:00 KST까지 공유되었는지 확인한다.",
      "Doyun의 failure triage note가 금요일 12:00 KST까지 action_items.md에 작성되었는지 확인한다.",
      "smoke 결과 공유 후 Hara가 generated tarball path를 확인했는지 확인한다.",
      "README install steps 검토 담당자를 지정할지 확인한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 수요일 내부 stretch goal을 언급할지 결정한다."
    ],
    "발명하지_말아야_할_내용": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "운영 장애",
      "법무 승인 요구사항",
      "명시되지 않은 owner",
      "명시되지 않은 deadline"
    ]
  },
  "non_invention_rules": {
    "고객": "고객 또는 외부 파트너는 언급되지 않았으므로 만들지 않는다.",
    "예산": "예산 정보는 언급되지 않았으므로 만들지 않는다.",
    "보안": "보안 사고는 언급되지 않았으므로 만들지 않는다.",
    "장애": "production outage는 언급되지 않았으므로 만들지 않는다.",
    "법무": "legal approval requirement는 언급되지 않았으므로 만들지 않는다.",
    "소유자": "README install steps 검토에는 owner가 지정되지 않았으므로 임의 배정하지 않는다.",
    "마감": "Hara의 tarball path 확인에는 정확한 deadline이 없으므로 임의 마감일을 만들지 않는다."
  }
}
